saidas = []
caso = []

def compara(tupla1, tupla2):
    # recebe duas tuplas e compara se a primeira vez antes ou não pro merge sort organizar
    if (tupla1[0] != tupla2[0]):
        return tupla1[0] == 'branco'
    if (tupla1[1] != tupla2[1]):
        if (tupla1[1] == 'P'):
            return True
        if (tupla1[1] == 'G'):
            return False
        if (tupla1[1] == 'M' and tupla2[1] == 'P'):
            return False
        else:
            return True
    return tupla1[2] < tupla2[2]


def merge_sort(ini, fim):
    if (ini == fim):
        return

    merge_sort(ini, int((ini + fim) / 2))
    merge_sort(int((ini + fim) / 2) + 1, fim)

    organizado = []

    j = int((ini + fim) / 2) + 1
    for i in range(ini, int((ini + fim) / 2) + 1):
        while j <= fim and not compara(caso[i], caso[j]):
            organizado.append(caso[j])
            j += 1
        organizado.append(caso[i])
    while j <= fim:
        organizado.append(caso[j])
        j += 1

    if len(organizado) != fim - ini + 1:
        print('ops isso n era pra acontecer', ini, fim, len(organizado))
        print(organizado)
        print(caso[ini:fim + 1])

    contador = 0
    for i in range(ini, fim + 1):
        caso[i] = organizado[contador]
        contador += 1


while True:
    N = int(input())
    if N == 0:
        break

    for i in range(N):
        nome = input()
        corEtamanho = input().split()
        caso.append((corEtamanho[0], corEtamanho[1], nome)) # cor, tamanho, nome

    merge_sort(0, N - 1)
    saidas.append(caso)
    caso = []


for i in range(len(saidas)):
    for j in range(len(saidas[i])):
        print(f'{saidas[i][j][0]} {saidas[i][j][1]} {saidas[i][j][2]}')
