solution:
import math

try:
    A = float(input())
    B = float(input())
    C = float(input())

    if A == 0:
        print("Impossivel calcular")
    else:
        Delta = B*B - 4*A*C

        if Delta < 0 and abs(Delta) > 1e-9:
            print("Impossivel calcular")
        else:
            Delta = max(Delta, 0.0)

            R1 = (-B + math.sqrt(Delta)) / (2*A)
            R2 = (-B - math.sqrt(Delta)) / (2*A)

            print(f"R1 = {R1:.5f}")
            print(f"R2 = {R2:.5f}")

except ValueError:
    print("Impossivel calcular")

