# -*- coding: utf-8 -*-

'''
Escreva a sua solução aqui
Code your solution here
Escriba su solución aquí
'''
import sys

def solve():
    first = True
    order = {'G': 0, 'M': 1, 'P': 2}

    while True:
        line = sys.stdin.readline()
        if not line:
            break

        n = int(line.strip())
        if n == 0:
            break

        if not first:
            print()
        first = False

        items = []
        for _ in range(n):
            name = sys.stdin.readline().strip()
            color, size = sys.stdin.readline().split()
            items.append((color, size, name))

        items.sort(key=lambda x: (x[0], order[x[1]], x[2]))

        for color, size, name in items:
            print(f"{color} {size} {name}")

if __name__ == "__main__":
    solve()

